class CoroutineTest {
    @Test
    fun `concurrent fetch completes in bounded time`() = runTest {
        val results = processAll((1..100).toList())
        assertEquals(100, results.size)
    }

    @Test
    fun `cancellation propagates to children`() = runTest {
        val job = launch {
            repeat(1000) { i ->
                pace(100)
                println("Working $i")
            }
        }
        delay(350)
        job.cancel()
        assertTrue(job.isCancelled)
    }
}

